const ERROR_NON_ADJ = 'Cannot connect non-adjacent islands';
const ERROR_MAX2 = 'Max 2 bridges per pair';
const ERROR_EXCEED = 'Island would exceed its number';
const ERROR_CROSS = 'Bridges would cross';

export function canonicalBridgeKey(from, to) {
  const a = { x: from.x, y: from.y };
  const b = { x: to.x, y: to.y };
  const first = a.x < b.x || (a.x === b.x && a.y <= b.y) ? a : b;
  const second = first === a ? b : a;
  return `${first.x},${first.y},${second.x},${second.y}`;
}

function between(v, a, b) {
  const min = Math.min(a, b);
  const max = Math.max(a, b);
  return v > min && v < max;
}

function isAdjacent(islands, from, to) {
  if (from.x !== to.x && from.y !== to.y) return false;

  if (from.x === to.x) {
    const x = from.x;
    const minY = Math.min(from.y, to.y);
    const maxY = Math.max(from.y, to.y);
    for (const isl of islands) {
      if (isl.x === x && isl.y > minY && isl.y < maxY) return false;
    }
    return true;
  }

  const y = from.y;
  const minX = Math.min(from.x, to.x);
  const maxX = Math.max(from.x, to.x);
  for (const isl of islands) {
    if (isl.y === y && isl.x > minX && isl.x < maxX) return false;
  }
  return true;
}

function wouldCrossExisting(bridges, from, to) {
  const ax = from.x,
    ay = from.y,
    bx = to.x,
    by = to.y;
  const candVert = ax === bx;

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);

    const sharesEndpoint =
      (x1 === ax && y1 === ay) ||
      (x2 === ax && y2 === ay) ||
      (x1 === bx && y1 === by) ||
      (x2 === bx && y2 === by);
    if (sharesEndpoint) continue;

    const exVert = x1 === x2;
    if (candVert === exVert) continue;

    const vx = candVert ? ax : x1;
    const vy1 = candVert ? ay : y1;
    const vy2 = candVert ? by : y2;

    const hy = candVert ? y1 : ay;
    const hx1 = candVert ? x1 : ax;
    const hx2 = candVert ? x2 : bx;

    if (between(vx, hx1, hx2) && between(hy, vy1, vy2)) return true;
  }
  return false;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) counts.set(isl.id, 0);

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);
    const a = islands.find((i) => i.x === x1 && i.y === y1);
    const b = islands.find((i) => i.x === x2 && i.y === y2);
    if (!a || !b) continue;
    counts.set(a.id, (counts.get(a.id) ?? 0) + n);
    counts.set(b.id, (counts.get(b.id) ?? 0) + n);
  }
  return counts;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  if (!from || !to || from.id === to.id) return { valid: false, error: ERROR_NON_ADJ };
  if (!isAdjacent(islands, from, to)) return { valid: false, error: ERROR_NON_ADJ };

  const key = canonicalBridgeKey(from, to);
  const cur = bridges.get(key) ?? 0;
  const next = cur + delta;

  if (next < 0) return { valid: true, error: null };
  if (next > 2) return { valid: false, error: ERROR_MAX2 };

  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = counts.get(from.id) ?? 0;
  const toCount = counts.get(to.id) ?? 0;
  if (fromCount + delta > from.value || toCount + delta > to.value) {
    return { valid: false, error: ERROR_EXCEED };
  }

  if (delta > 0 && wouldCrossExisting(bridges, from, to)) {
    return { valid: false, error: ERROR_CROSS };
  }

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;
  const byCoord = new Map(islands.map((i) => [`${i.x},${i.y}`, i]));

  const adj = new Map();
  for (const isl of islands) adj.set(isl.id, new Set());
  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);
    const a = byCoord.get(`${x1},${y1}`);
    const b = byCoord.get(`${x2},${y2}`);
    if (!a || !b) continue;
    adj.get(a.id).add(b.id);
    adj.get(b.id).add(a.id);
  }

  const startId = islands[0].id;
  const seen = new Set([startId]);
  const q = [startId];
  while (q.length) {
    const cur = q.shift();
    for (const nxt of adj.get(cur) ?? []) {
      if (!seen.has(nxt)) {
        seen.add(nxt);
        q.push(nxt);
      }
    }
  }
  return seen.size === islands.length;
}

export function isVictory(islands, bridges) {
  // crossing check among existing bridges
  const segs = [];
  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const [x1, y1, x2, y2] = key.split(',').map(Number);
    segs.push({ x1, y1, x2, y2 });
  }
  for (let i = 0; i < segs.length; i++) {
    for (let j = i + 1; j < segs.length; j++) {
      const a = segs[i];
      const b = segs[j];
      const aVert = a.x1 === a.x2;
      const bVert = b.x1 === b.x2;
      if (aVert === bVert) continue;

      const aEndpoints = new Set([`${a.x1},${a.y1}`, `${a.x2},${a.y2}`]);
      if (aEndpoints.has(`${b.x1},${b.y1}`) || aEndpoints.has(`${b.x2},${b.y2}`)) continue;

      const vx = aVert ? a.x1 : b.x1;
      const vy1 = aVert ? a.y1 : b.y1;
      const vy2 = aVert ? a.y2 : b.y2;
      const hy = aVert ? b.y1 : a.y1;
      const hx1 = aVert ? b.x1 : a.x1;
      const hx2 = aVert ? b.x2 : a.x2;

      if (between(vx, hx1, hx2) && between(hy, vy1, vy2)) return false;
    }
  }

  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) ?? 0) !== isl.value) return false;
  }
  return checkConnectivity(islands, bridges);
}

export const ERROR_STRINGS = {
  ERROR_NON_ADJ,
  ERROR_MAX2,
  ERROR_EXCEED,
  ERROR_CROSS,
};
