import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles, puzzleOptions } from './data/puzzles';
import {
  canAddBridge,
  canonicalBridgeKey,
  checkConnectivity,
  computeCurrentCounts,
  isVictory,
} from './utils/hashiLogic';

const CELL = 40;
const SVG_W = 800;
const SVG_H = 600;

function getNeighbors(islands, from) {
  const candidates = { left: null, right: null, up: null, down: null };
  for (const isl of islands) {
    if (isl.id === from.id) continue;
    if (isl.y === from.y) {
      if (isl.x < from.x) {
        if (!candidates.left || isl.x > candidates.left.x) candidates.left = isl;
      } else if (isl.x > from.x) {
        if (!candidates.right || isl.x < candidates.right.x) candidates.right = isl;
      }
    }
    if (isl.x === from.x) {
      if (isl.y < from.y) {
        if (!candidates.up || isl.y > candidates.up.y) candidates.up = isl;
      } else if (isl.y > from.y) {
        if (!candidates.down || isl.y < candidates.down.y) candidates.down = isl;
      }
    }
  }
  return candidates;
}

function bridgeLinesForPair(from, to, count) {
  if (!count) return [];
  const x1 = from.x * CELL;
  const y1 = from.y * CELL;
  const x2 = to.x * CELL;
  const y2 = to.y * CELL;
  const vertical = from.x === to.x;
  const offset = 5;

  if (count === 1) return [{ x1, y1, x2, y2 }];
  if (vertical) {
    return [
      { x1: x1 - offset, y1, x2: x2 - offset, y2 },
      { x1: x1 + offset, y1, x2: x2 + offset, y2 },
    ];
  }
  return [
    { x1, y1: y1 - offset, x2, y2: y2 - offset },
    { x1, y1: y1 + offset, x2, y2: y2 + offset },
  ];
}

export default function App() {
  const [puzzleKey, setPuzzleKey] = useState('Easy');
  const islands = puzzles[puzzleKey].islands;

  const [bridges, setBridges] = useState(() => new Map());
  const [selectedId, setSelectedId] = useState(null);
  const [cursorId, setCursorId] = useState(0);
  const [error, setError] = useState(null);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);
  const selectionMode = selectedId !== null;

  const islandsById = useMemo(() => {
    const m = new Map();
    for (const isl of islands) m.set(isl.id, isl);
    return m;
  }, [islands]);

  const cursorIsland = islandsById.get(cursorId) ?? islands[0];

  const resetAllStateForPuzzle = (nextPuzzleKey) => {
    setPuzzleKey(nextPuzzleKey);
    setBridges(new Map());
    setSelectedId(null);
    setError(null);
    setCursorId(0);
  };

  const resetBridgesOnly = () => {
    setBridges(new Map());
    setSelectedId(null);
    setError(null);
    setCursorId(0);
  };

  const applyBridgeDelta = (from, to, delta) => {
    const res = canAddBridge(islands, bridges, from, to, delta);
    if (!res.valid) {
      setError(res.error);
      return false;
    }
    setError(null);
    const key = canonicalBridgeKey(from, to);
    setBridges((prev) => {
      const next = new Map(prev);
      const cur = next.get(key) ?? 0;
      const val = cur + delta;
      if (val <= 0) next.delete(key);
      else next.set(key, val);
      return next;
    });
    setSelectedId(null);
    setCursorId(0);
    return true;
  };

  const cycleBridge = (from, to) => {
    const key = canonicalBridgeKey(from, to);
    const cur = bridges.get(key) ?? 0;
    const next = (cur + 1) % 3;
    const delta = next - cur;
    if (delta === 0) return true;
    return applyBridgeDelta(from, to, delta);
  };

  const removeBridge = (from, to) => {
    const key = canonicalBridgeKey(from, to);
    const cur = bridges.get(key) ?? 0;
    if (!cur) return true;
    setError(null);
    setBridges((prev) => {
      const next = new Map(prev);
      next.delete(key);
      return next;
    });
    setSelectedId(null);
    setCursorId(0);
    return true;
  };

  const onIslandClick = (isl) => {
    if (selectedId === null) {
      setSelectedId(isl.id);
      setCursorId(isl.id);
      return;
    }
    if (selectedId === isl.id) return;
    const from = islandsById.get(selectedId);
    const to = isl;
    cycleBridge(from, to);
  };

  const onIslandRemoveGesture = (e, isl) => {
    e.preventDefault();
    if (selectedId === null) return;
    if (selectedId === isl.id) return;
    const from = islandsById.get(selectedId);
    removeBridge(from, isl);
  };

  const keyHandlerRef = useRef(null);
  keyHandlerRef.current = (e) => {
    if (e.key === 'Escape') {
      setSelectedId(null);
      return;
    }

    const cur = islandsById.get(cursorId) ?? islands[0];
    if (!cur) return;
    const neighbors = getNeighbors(islands, cur);

    const moveCursor = (dir) => {
      const next = neighbors[dir];
      if (!next) return;
      setCursorId(next.id);
    };

    if (e.key === 'ArrowLeft') moveCursor('left');
    else if (e.key === 'ArrowRight') moveCursor('right');
    else if (e.key === 'ArrowUp') moveCursor('up');
    else if (e.key === 'ArrowDown') moveCursor('down');
    else if (e.key === 'Enter') {
      if (selectedId === null) {
        setSelectedId(cursorId);
      } else {
        const from = islandsById.get(selectedId);
        const to = islandsById.get(cursorId);
        if (from && to && from.id !== to.id) cycleBridge(from, to);
      }
    }
  };

  useEffect(() => {
    const onKeyDown = (e) => keyHandlerRef.current?.(e);
    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, []);

  useEffect(() => {
    setCursorId(0);
  }, [puzzleKey]);

  const renderedBridges = useMemo(() => {
    const byCoord = new Map(islands.map((i) => [`${i.x},${i.y}`, i]));
    const lines = [];
    for (const [key, n] of bridges.entries()) {
      const [x1, y1, x2, y2] = key.split(',').map(Number);
      const a = byCoord.get(`${x1},${y1}`);
      const b = byCoord.get(`${x2},${y2}`);
      if (!a || !b) continue;
      const segs = bridgeLinesForPair(a, b, n);
      for (let idx = 0; idx < segs.length; idx++) lines.push({ ...segs[idx], k: `${key}:${idx}` });
    }
    return lines;
  }, [islands, bridges]);

  const cursorPx = {
    x: (cursorIsland?.x ?? 0) * CELL,
    y: (cursorIsland?.y ?? 0) * CELL,
  };

  const connected = useMemo(() => checkConnectivity(islands, bridges), [islands, bridges]);

  return (
    <>
      <div className="ui-bar">
        <label>
          Puzzle:{' '}
          <select value={puzzleKey} onChange={(e) => resetAllStateForPuzzle(e.target.value)}>
            {puzzleOptions.map((opt) => (
              <option key={opt.key} value={opt.key}>
                {opt.label}
              </option>
            ))}
          </select>
        </label>
        <button onClick={resetBridgesOnly}>Reset</button>
        <div style={{ marginLeft: 8 }}>{connected ? 'Connected' : 'Not connected'}</div>
      </div>

      {error ? <div className="error-message">{error}</div> : null}
      {!error && victory ? <div className="victory-banner">SOLVED!</div> : null}

      <svg width={SVG_W} height={SVG_H} style={{ position: 'fixed', left: 0, top: 0, zIndex: 1 }}>
        {renderedBridges.map((ln) => (
          <line
            key={ln.k}
            x1={ln.x1}
            y1={ln.y1}
            x2={ln.x2}
            y2={ln.y2}
            stroke="#00ff66"
            strokeWidth={3}
          />
        ))}

        <rect
          x={cursorPx.x - 16}
          y={cursorPx.y - 16}
          width={32}
          height={32}
          fill="none"
          stroke="#00ff66"
          strokeWidth={2}
          strokeDasharray={selectionMode ? '4 2' : '2 2'}
        />

        {islands.map((isl) => {
          const cx = isl.x * CELL;
          const cy = isl.y * CELL;
          const isSel = selectedId === isl.id;
          const curCount = counts.get(isl.id) ?? 0;
          return (
            <g key={isl.id}>
              <circle
                cx={cx}
                cy={cy}
                r={14}
                fill="#000"
                stroke="#00ff66"
                strokeWidth={isSel ? 3 : 2}
                onClick={(e) => {
                  if (e.ctrlKey) return onIslandRemoveGesture(e, isl);
                  onIslandClick(isl);
                }}
                onContextMenu={(e) => onIslandRemoveGesture(e, isl)}
                style={{ cursor: 'pointer' }}
              />
              <text x={cx} y={cy + 5} textAnchor="middle" fontSize={14} fill="#00ff66">
                {isl.value}
              </text>
              <text x={cx} y={cy + 28} textAnchor="middle" fontSize={10} fill="#00ff66">
                {curCount}/{isl.value}
              </text>
            </g>
          );
        })}
      </svg>
    </>
  );
}
